        "description": "List all images available locally.",
        "parameters": {},
        "required": [],
        "returns": "Promise<DockerImage[]>",
        "examples": [
          {
            "language": "ts",
            "code": "const images = await docker.listImages()\nconsole.log(images.map(i => `${i.repository}:${i.tag}`))"
          }
        ]
